import { expect, test } from '@playwright/test';
import { LoginPage } from '../pages/login.page';
import { resetRateLimiter, seedUser } from '../fixtures/auth';

test.describe('Login with email and password', () => {
  let login: LoginPage;

  test.beforeEach(async ({ page }) => {
    await resetRateLimiter(page);
    await seedUser(page, { email: 'casey@example.com', password: 'correct horse battery' });
    login = new LoginPage(page);
    await login.goto();
  });

  test('happy path redirects to /dashboard within 2s @p1', async ({ page }) => {
    const start = Date.now();
    await login.submit('casey@example.com', 'correct horse battery');
    await expect(page).toHaveURL(/\/dashboard/);
    expect(Date.now() - start).toBeLessThan(2000);
    const cookies = await page.context().cookies();
    const session = cookies.find((c) => c.name === '__Host-session');
    expect(session?.httpOnly).toBe(true);
  });

  test('wrong password shows generic error and clears password field @p1', async () => {
    await login.submit('casey@example.com', 'hunter2');
    await expect(login.error).toHaveText('Email or password is incorrect');
    await expect(login.email).toHaveValue('casey@example.com');
    await expect(login.password).toHaveValue('');
  });

  test('unknown email shows the same generic error @security', async () => {
    await login.submit('ghost@nowhere.example', 'whatever');
    await expect(login.error).toHaveText('Email or password is incorrect');
  });

  test('empty fields are caught client-side', async ({ page }) => {
    await login.submitForm();
    await expect(login.emailError).toHaveText('Email is required');
    await expect(login.passwordError).toHaveText('Password is required');
    // form did not POST
    expect(page.url()).toContain('/login');
  });
});

import { expect, test } from '@playwright/test';
import { LoginPage } from '../pages/login.page';
import { resetRateLimiter, seedUser } from '../fixtures/auth';

test('five failed attempts locks the account and shows reset-password link @rate-limit', async ({ page }) => {
  await resetRateLimiter(page);
  await seedUser(page, { email: 'casey@example.com', password: 'correct horse battery' });
  const login = new LoginPage(page);
  await login.goto();
  for (let i = 0; i < 5; i++) {
    await login.submit('casey@example.com', `wrong-${i}`);
  }
  await expect(login.error).toHaveText('Account temporarily locked');
  await expect(login.resetPasswordLink).toBeVisible();
});

import { expect, test } from '@playwright/test';
import { signInAs } from '../fixtures/auth';

test('session persists across a hard reload @p1', async ({ page }) => {
  await signInAs(page, 'casey@example.com', 'correct horse battery');
  await expect(page).toHaveURL(/\/dashboard/);
  await page.reload({ waitUntil: 'load' });
  await expect(page).toHaveURL(/\/dashboard/);
  await expect(page.getByTestId('header-user')).toContainText('casey@example.com');
});
